// Live updates from background (best-effort; popup can still render from stored meta)
chrome.runtime.onMessage.addListener((msg: any) => {
  const m = msg || {};
  if (m.type === 'VKX_POPUP_TASK_UPDATE') {
    const key = String(m.key || '') as TaskKey;
    if (taskUi[key]) {
      const meta: TaskMeta = {
        key,
        state: m.state as TaskState,
        ok: typeof m.ok === 'boolean' ? m.ok : undefined,
        processed: Number.isFinite(Number(m.processed)) ? Number(m.processed) : undefined,
        total: Number.isFinite(Number(m.total)) ? Number(m.total) : undefined,
        note: typeof m.note === 'string' ? m.note : undefined,
        error: m.error ? { code: Number(m.error.code), msg: String(m.error.msg || '') } : undefined
      };
      setTaskMeta(meta);

      if (meta.state === 'running') activeTask = key;
      if (meta.state === 'done' || meta.state === 'blocked' || meta.state === 'error') {
        if (activeTask === key) activeTask = null;
        refreshPopupMeta().catch(() => {});
      }

      if (m.live && typeof m.live === 'object') {
        lastPopupMeta = { ...(lastPopupMeta || { ok: true }), live: m.live };
      }

      setSession(
        lastPopupMeta?.busy,
        (m.live && typeof m.live === 'object') ? m.live : lastPopupMeta?.live
      );
    }
  }
});

